class Solution {
    public int countNumbers(String l, String r, int b) {
        int count = 0;
        int numL = Integer.parseInt(l, b);
        int numR = Integer.parseInt(r, b);
        while (numL <= numR) {
            int num = numL % b;
            count += (numL / b) % 2;
            numL = numR % b;
            numR = numR / b;
            count += (numR / b) % 2;
            numL = numL / b;
            numR = numR * b;
        }
        return count;
    }
}
